
import { Component, Prop, h, Event, EventEmitter, State, Element, Watch } from '@stencil/core';

@Component({
  tag: 'wdpr-pagination',
  shadow: true,
})
export class WdprPagination {

  private readonly ELLIPSIS = '...' as const;
  private _resizeObserver: ResizeObserver | null = null;
  private _resizeDebounceTimer: ReturnType<typeof setTimeout> | null = null;
  private _lastContainerWidth: number = 0;

  @Element() el: HTMLWdprPaginationElement;
  @State() _calculatedMaxVisibleItems: number = 10;
  @Prop() totalPages: number = 1;
  @Prop({ mutable: true }) currentPage: number = 1;
  @Prop() showNavControls: boolean = true;
  @Prop() maxVisibleItems: number = 10;
  @Prop() hidePaginationGroup: boolean = false;
  @Prop() collapsed: boolean = true;
  @Event() wdprPageChange: EventEmitter<{page: number}>;

  @Watch('maxVisibleItems')
  @Watch('showNavControls')
  handleConfigChange() {
    this._calculateVisibleItems();
  }

  componentDidLoad() {
    this._setupResizeObserver();
    this._calculateVisibleItems();
  }

  disconnectedCallback() {
    this._cleanupResizeObserver();
  }

  private _setupResizeObserver() {
    this._resizeObserver = new ResizeObserver(entries => {
      for (const entry of entries) {
        const newWidth = entry.contentRect.width;

        if (Math.abs(newWidth - this._lastContainerWidth) > 1) {
          this._lastContainerWidth = newWidth;
          this._debouncedCalculateVisibleItems();
        }
      }
    });

    this._resizeObserver.observe(this.el);
  }

  private _cleanupResizeObserver() {
    if (this._resizeObserver) {
      this._resizeObserver.disconnect();
      this._resizeObserver = null;
    }

    if (this._resizeDebounceTimer) {
      clearTimeout(this._resizeDebounceTimer);
      this._resizeDebounceTimer = null;
    }
  }

  private _debouncedCalculateVisibleItems() {
    if (this._resizeDebounceTimer) {
      clearTimeout(this._resizeDebounceTimer);
    }

    this._resizeDebounceTimer = setTimeout(() => {
      this._calculateVisibleItems();
    }, 16);
  }

  private _calculateVisibleItems() {
    const containerWidth = this.el.getBoundingClientRect().width;
    if (containerWidth === 0) return;

    const itemWidth = 48;
    const navControlsWidth = this.showNavControls ? 260 : 0;
    const availableWidth = containerWidth - navControlsWidth;
    const fittableItems = Math.floor(availableWidth / itemWidth);
    this._calculatedMaxVisibleItems = Math.max(1, Math.min(fittableItems, this.maxVisibleItems));
  }

  private _handlePageClick(page: number) {
    
    if (page >= 1 && page <= this.totalPages && page !== this.currentPage) {
        this.currentPage = page;
        this.wdprPageChange.emit( { page });
    }
  }

  private _getPaginationRange(): (number | string)[] {
    const totalPageCount = this.totalPages;
    const maxItems = this._calculatedMaxVisibleItems;

    if (totalPageCount <= maxItems || this.collapsed === false) {
      return Array.from({ length: totalPageCount }, (_, i) => i + 1);
    }

    const siblingCount = Math.max(1, Math.floor((maxItems - 4) / 2));
    
    const leftSiblingIndex = Math.max(this.currentPage - siblingCount, 1);
    const rightSiblingIndex = Math.min(this.currentPage + siblingCount, totalPageCount);

    const showLeftDots = leftSiblingIndex > 2;
    const showRightDots = rightSiblingIndex < totalPageCount - 1;

    if (!showLeftDots && !showRightDots) {
         return Array.from({ length: totalPageCount }, (_, i) => i + 1);
    }

    if (!showLeftDots && showRightDots) {
      const leftItemCount = maxItems - 2;
      const leftRange = Array.from({ length: leftItemCount }, (_, i) => i + 1);

      return [...leftRange, this.ELLIPSIS, totalPageCount];
    }

    if (showLeftDots && !showRightDots) {
      const rightItemCount = maxItems - 2;
      const rightRange = Array.from({ length: rightItemCount }, (_, i) => totalPageCount - rightItemCount + i + 1);

      return [1, this.ELLIPSIS, ...rightRange];
    }

    const middleCount = maxItems - 4;
    const leftSibling = Math.max(this.currentPage - Math.floor(middleCount/2), 2);
    const middleRange = Array.from({ length: middleCount }, (_, i) => leftSibling + i);

    return [1, this.ELLIPSIS, ...middleRange, this.ELLIPSIS, totalPageCount];
  }

  render() {
    return (
      <nav 
        class="flex items-center w-full justify-center" 
        role="navigation"
        aria-label="Pagination"
      >
        {this.showNavControls && (
          <wdpr-button
            variant="text" 
            disabled={this.currentPage === 1}
            onClick={() => this._handlePageClick(this.currentPage - 1)}
            a11y-label="Previous Page"
            class="mr-200"
            size="medium"
          >
            <div slot="leading-icon">
              <wdpr-icon-library icon="previous" decorative></wdpr-icon-library>
            </div>
            Previous
          </wdpr-button>
        )}

        {!this.hidePaginationGroup && (
            this._calculatedMaxVisibleItems < 5 && this.collapsed ? (
              <div class="flex items-center py-150 px-100 h-[40px]" aria-live="polite" aria-atomic="true">
                  <span class="component-large text-text-body">
                      {this.currentPage} / {this.totalPages}
                  </span>
              </div>
            ) : (
              <ul class="flex items-center gap-100 m-0 p-0 list-none">
                  {this._getPaginationRange().map((page, index) => {
                      if (page === this.ELLIPSIS) {
                          return (
                            <li key={`ellipsis-${index}`}>
                              <wdpr-pagination-readonly />
                            </li>
                          );
                      }

                      const pageNumber = page;

                      return (
                          <li key={pageNumber}>
                                <wdpr-pagination-item
                                  page={pageNumber}
                                  selected={pageNumber === this.currentPage}
                                  aria-current={pageNumber === this.currentPage ? 'page' : undefined}
                                  onWdprClick={() => this._handlePageClick(pageNumber as number)}
                                  a11y-label={`Page ${pageNumber}`}
                                />
                          </li>
                      );
                  })}
              </ul>
            )
        )}

        {this.showNavControls && (
          <wdpr-button
            variant="text"
            disabled={this.currentPage === this.totalPages}
            onClick={() => this._handlePageClick(this.currentPage + 1)}
            a11y-label="Next Page"
            class="ml-200"
            size="medium"
          >
            Next
            <div slot="trailing-icon">
              <wdpr-icon-library icon="next" decorative></wdpr-icon-library>
            </div>
          </wdpr-button>
        )}
      </nav>
    );
  }
}
